import redis

# Connect to Redis server
redis_client = redis.Redis()

# Get Lua script from user input
lua_script = input("Enter Lua script: ")

# Define user parameters
user_params = [10, "my_key"]

# Execute Lua script using redis.eval()
result = redis_client.eval(lua_script, user_params)

